{
  "name": "D&D 5e Auto-Sheet",
  "description": "A dynamic Dungeons & Dragons 5th Edition character sheet that automatically calculates modifiers, skills, and combat statistics based on your inputs. Includes AI-powered backstory generation."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

