export type AbilityName = 'STR' | 'DEX' | 'CON' | 'INT' | 'WIS' | 'CHA';

export interface AbilityScores {
  STR: number;
  DEX: number;
  CON: number;
  INT: number;
  WIS: number;
  CHA: number;
}

export interface SkillDefinition {
  name: string;
  ability: AbilityName;
}

export interface CharacterData {
  name: string;
  race: string;
  class: string;
  level: number;
  alignment: string;
  background: string;
  playerName: string;
  experience: string;

  // Stats
  abilities: AbilityScores;

  // Proficiencies (Set of strings matching skill names or ability names for saves)
  proficiencies: Set<string>;
  expertises: Set<string>; // For skills with double proficiency

  // Combat Override (if null, auto-calc)
  acOverride: number | null;
  hpCurrent: number;
  hpMaxOverride: number | null;

  // Flavor
  backstory: string;
}

export const INITIAL_CHARACTER: CharacterData = {
  name: "",
  race: "",
  class: "Fighter",
  level: 1,
  alignment: "",
  background: "",
  playerName: "",
  experience: "0",
  abilities: {
    STR: 10,
    DEX: 10,
    CON: 10,
    INT: 10,
    WIS: 10,
    CHA: 10,
  },
  proficiencies: new Set(),
  expertises: new Set(),
  acOverride: null,
  hpCurrent: 10,
  hpMaxOverride: null,
  backstory: ""
};

import { AbilityScores, AbilityName } from '../types';
import { HIT_DICE } from '../constants';

export const calculateModifier = (score: number): number => {
  return Math.floor((score - 10) / 2);
};

export const calculateProficiencyBonus = (level: number): number => {
  if (level < 1) return 2;
  return Math.floor((level - 1) / 4) + 2;
};

export const formatModifier = (mod: number): string => {
  return mod >= 0 ? `+${mod}` : `${mod}`;
};

export const calculatePassivePerception = (
  wisScore: number,
  profBonus: number,
  isProficient: boolean
): number => {
  return 10 + calculateModifier(wisScore) + (isProficient ? profBonus : 0);
};

export const calculateMaxHP = (
  charClass: string,
  level: number,
  conScore: number,
  override: number | null
): number => {
  if (override !== null) return override;

  const hitDie = HIT_DICE[charClass] || 8; // Default to d8 if unknown
  const conMod = calculateModifier(conScore);

  // Level 1: Max Hit Die + CON
  // Level 2+: Average Hit Die (rounded up) + CON

  const levelOneHP = hitDie + conMod;
  const subsequentHP = (Math.ceil(hitDie / 2) + 1 + conMod) * (level - 1);

  const total = levelOneHP + subsequentHP;
  return total > 0 ? total : 1; // Minimum 1 HP
};

import { GoogleGenAI } from "@google/genai";
import { CharacterData } from '../types';
import { calculateModifier } from '../utils/dndCalculations';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateBackstory = async (character: CharacterData): Promise<string> => {
  const modelId = 'gemini-3-flash-preview';

  const abilitiesStr = Object.entries(character.abilities)
    .map(([key, val]) => `${key}:${val} (${calculateModifier(val)})`)
    .join(', ');

  const prompt = `
    Create a compelling, short (approx 150 words) backstory for a D&D 5e character with the following details:
    Name: ${character.name || "Unnamed"}
    Race: ${character.race || "Unknown"}
    Class: ${character.class} (Level ${character.level})
    Background: ${character.background || "Unknown"}
    Alignment: ${character.alignment || "Neutral"}
    Ability Scores: ${abilitiesStr}

    The backstory should explain why they became an adventurer and hint at their personality. 
    Keep it suitable for a fantasy setting.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
    });
    return response.text || "Failed to generate backstory.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error connecting to the lore archives (API Error). Please try again.";
  }
};

export const suggestName = async (race: string, charClass: string): Promise<string> => {
   const modelId = 'gemini-3-flash-preview';
   const prompt = `Suggest a single, creative fantasy name for a ${race} ${charClass}. Return ONLY the name, nothing else.`;

   try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
    });
    return (response.text || "").trim().replace(/\.|"|'/g, '');
   } catch (error) {
     return "Nameless One";
   }
}

import React from 'react';
import { AbilityName } from '../types';
import { calculateModifier, formatModifier } from '../utils/dndCalculations';

interface AbilityScoreProps {
  ability: AbilityName;
  score: number;
  onChange: (val: number) => void;
  savingThrowProficient: boolean;
  onToggleSave: () => void;
  profBonus: number;
}

export const AbilityScore: React.FC<AbilityScoreProps> = ({
  ability,
  score,
  onChange,
  savingThrowProficient,
  onToggleSave,
  profBonus,
}) => {
  const mod = calculateModifier(score);
  const saveMod = mod + (savingThrowProficient ? profBonus : 0);

  return (
    <div className="flex flex-col items-center bg-dnd-slate p-3 rounded-lg border border-gray-700 shadow-md">
      <h3 className="text-dnd-gold font-bold text-lg mb-1">{ability}</h3>

      <div className="relative w-full flex justify-center mb-2">
        <input
          type="number"
          value={score}
          onChange={(e) => onChange(parseInt(e.target.value) || 0)}
          className="w-16 h-12 text-center text-2xl font-bold bg-white text-black rounded focus:ring-2 focus:ring-dnd-gold outline-none"
        />
        <div className="absolute -bottom-4 bg-dnd-dark border border-gray-500 rounded-full w-10 h-10 flex items-center justify-center font-bold text-white shadow">
          {formatModifier(mod)}
        </div>
      </div>

      <div className="mt-5 w-full flex items-center justify-between text-xs px-1">
        <span className="text-gray-400 uppercase tracking-wide">Save</span>
        <div className="flex items-center gap-1">
            <span className="font-mono text-sm">{formatModifier(saveMod)}</span>
            <input 
                type="checkbox" 
                checked={savingThrowProficient} 
                onChange={onToggleSave}
                className="accent-dnd-gold h-4 w-4 cursor-pointer"
            />
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { AbilityScores, CharacterData, SkillDefinition } from '../types';
import { SKILLS } from '../constants';
import { calculateModifier, formatModifier } from '../utils/dndCalculations';

interface SkillListProps {
  abilities: AbilityScores;
  profBonus: number;
  proficiencies: Set<string>;
  expertises: Set<string>;
  onToggleProficiency: (skill: string) => void;
}

export const SkillList: React.FC<SkillListProps> = ({
  abilities,
  profBonus,
  proficiencies,
  expertises,
  onToggleProficiency,
}) => {
  return (
    <div className="bg-dnd-slate rounded-lg border border-gray-700 p-4">
      <h3 className="text-dnd-gold font-serif text-xl border-b border-gray-600 mb-3 pb-1">Skills</h3>
      <div className="space-y-1">
        {SKILLS.map((skill) => {
          const isProficient = proficiencies.has(skill.name);
          const abilityScore = abilities[skill.ability];
          const abilityMod = calculateModifier(abilityScore);

          let totalMod = abilityMod;
          if (isProficient) totalMod += profBonus;

          return (
            <div key={skill.name} className="flex items-center hover:bg-gray-700 p-1 rounded transition-colors group">
              <input
                type="checkbox"
                checked={isProficient}
                onChange={() => onToggleProficiency(skill.name)}
                className="accent-dnd-gold h-4 w-4 mr-2 cursor-pointer"
              />
              <span className="font-mono w-8 text-right mr-3 text-dnd-gold font-bold">
                {formatModifier(totalMod)}
              </span>
              <span className="flex-1 text-sm text-gray-200 group-hover:text-white">
                {skill.name} <span className="text-xs text-gray-500 ml-1">({skill.ability})</span>
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { CharacterData } from '../types';
import { CLASSES, ALIGNMENTS } from '../constants';
import { suggestName } from '../services/geminiService';

interface HeaderProps {
  data: CharacterData;
  onChange: (field: keyof CharacterData, value: any) => void;
}

export const Header: React.FC<HeaderProps> = ({ data, onChange }) => {
  const [loadingName, setLoadingName] = useState(false);

  const handleSuggestName = async () => {
    if (!data.race) {
        alert("Please select a race first to generate a suitable name.");
        return;
    }
    setLoadingName(true);
    const newName = await suggestName(data.race, data.class);
    onChange('name', newName);
    setLoadingName(false);
  };

  return (
    <div className="bg-dnd-slate p-4 rounded-lg border border-gray-700 shadow-lg mb-6">
      <div className="grid grid-cols-1 md:grid-cols-12 gap-4">

        {/* Name Section */}
        <div className="md:col-span-4 flex flex-col gap-1">
            <label className="text-xs text-gray-400 uppercase font-bold">Character Name</label>
            <div className="flex gap-2">
                <input
                    type="text"
                    value={data.name}
                    onChange={(e) => onChange('name', e.target.value)}
                    className="flex-1 bg-dnd-dark border border-gray-600 rounded px-3 py-2 text-white focus:border-dnd-gold outline-none font-serif text-lg"
                    placeholder="Enter Name"
                />
                <button 
                    onClick={handleSuggestName}
                    disabled={loadingName}
                    className="bg-gray-700 hover:bg-dnd-gold hover:text-black text-xs px-2 rounded border border-gray-600 transition-colors"
                    title="AI Suggest Name"
                >
                    {loadingName ? "..." : "AI"}
                </button>
            </div>
        </div>

        {/* Basic Dropdowns */}
        <div className="md:col-span-8 grid grid-cols-2 md:grid-cols-4 gap-4">
             <div className="flex flex-col gap-1">
                <label className="text-xs text-gray-400 uppercase font-bold">Class</label>
                <select
                    value={data.class}
                    onChange={(e) => onChange('class', e.target.value)}
                    className="bg-dnd-dark border border-gray-600 rounded px-2 py-2 text-white focus:border-dnd-gold outline-none"
                >
                    {CLASSES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
            </div>

            <div className="flex flex-col gap-1">
                <label className="text-xs text-gray-400 uppercase font-bold">Level</label>
                <input
                    type="number"
                    min="1"
                    max="20"
                    value={data.level}
                    onChange={(e) => onChange('level', parseInt(e.target.value) || 1)}
                    className="bg-dnd-dark border border-gray-600 rounded px-2 py-2 text-white focus:border-dnd-gold outline-none"
                />
            </div>

            <div className="flex flex-col gap-1">
                <label className="text-xs text-gray-400 uppercase font-bold">Race</label>
                <input
                    type="text"
                    value={data.race}
                    onChange={(e) => onChange('race', e.target.value)}
                    placeholder="e.g. Human"
                    className="bg-dnd-dark border border-gray-600 rounded px-2 py-2 text-white focus:border-dnd-gold outline-none"
                />
            </div>

            <div className="flex flex-col gap-1">
                <label className="text-xs text-gray-400 uppercase font-bold">Alignment</label>
                <select
                    value={data.alignment}
                    onChange={(e) => onChange('alignment', e.target.value)}
                    className="bg-dnd-dark border border-gray-600 rounded px-2 py-2 text-white focus:border-dnd-gold outline-none text-sm"
                >
                    <option value="">Select...</option>
                    {ALIGNMENTS.map(a => <option key={a} value={a}>{a}</option>)}
                </select>
            </div>

             <div className="flex flex-col gap-1">
                <label className="text-xs text-gray-400 uppercase font-bold">Background</label>
                <input
                    type="text"
                    value={data.background}
                    onChange={(e) => onChange('background', e.target.value)}
                    placeholder="e.g. Soldier"
                    className="bg-dnd-dark border border-gray-600 rounded px-2 py-2 text-white focus:border-dnd-gold outline-none"
                />
            </div>

             <div className="flex flex-col gap-1">
                <label className="text-xs text-gray-400 uppercase font-bold">Player Name</label>
                <input
                    type="text"
                    value={data.playerName}
                    onChange={(e) => onChange('playerName', e.target.value)}
                    className="bg-dnd-dark border border-gray-600 rounded px-2 py-2 text-white focus:border-dnd-gold outline-none"
                />
            </div>

             <div className="flex flex-col gap-1 col-span-2">
                <label className="text-xs text-gray-400 uppercase font-bold">Experience Points</label>
                <input
                    type="text"
                    value={data.experience}
                    onChange={(e) => onChange('experience', e.target.value)}
                    className="bg-dnd-dark border border-gray-600 rounded px-2 py-2 text-white focus:border-dnd-gold outline-none"
