import React from 'react';
import { CharacterData } from '../types';
import { calculateModifier, calculateMaxHP } from '../utils/dndCalculations';

interface VitalsProps {
  data: CharacterData;
  onChange: (field: keyof CharacterData, value: any) => void;
  profBonus: number;
}

export const Vitals: React.FC<VitalsProps> = ({ data, onChange, profBonus }) => {
  const dexMod = calculateModifier(data.abilities.DEX);
  const conMod = calculateModifier(data.abilities.CON);
  const wisMod = calculateModifier(data.abilities.WIS);

  // Calculate Derived Stats
  const calculatedAC = 10 + dexMod;
  const finalAC = data.acOverride !== null ? data.acOverride : calculatedAC;

  const maxHP = calculateMaxHP(data.class, data.level, data.abilities.CON, data.hpMaxOverride);

  const initiative = dexMod;

  // Passive Perception (10 + Wis Mod + Prof if applicable)
  // Checking if 'Perception' is in proficiencies
  const perceptionProf = data.proficiencies.has('Perception');
  const passivePerception = 10 + wisMod + (perceptionProf ? profBonus : 0);

  return (
    <div className="grid grid-cols-3 gap-3 mb-6">
      {/* AC */}
      <div className="bg-dnd-slate border-2 border-gray-600 rounded-lg p-2 flex flex-col items-center justify-between relative group">
        <span className="text-xs text-gray-400 uppercase font-bold">Armor Class</span>
        <div className="flex items-center justify-center flex-1 w-full">
            <span className="text-3xl font-bold text-white font-serif">{finalAC}</span>
        </div>
        <div className="absolute top-1 right-1 opacity-0 group-hover:opacity-100 transition-opacity">
            <input 
                type="number" 
                className="w-10 text-xs text-black bg-white rounded p-1"
                placeholder="Ovr"
                value={data.acOverride ?? ''}
                onChange={(e) => {
                    const val = e.target.value === '' ? null : parseInt(e.target.value);
                    onChange('acOverride', val);
                }}
            />
        </div>
      </div>

      {/* Initiative */}
      <div className="bg-dnd-slate border-2 border-gray-600 rounded-lg p-2 flex flex-col items-center">
        <span className="text-xs text-gray-400 uppercase font-bold">Initiative</span>
        <span className="text-3xl font-bold text-white font-serif my-auto">
            {initiative >= 0 ? `+${initiative}` : initiative}
        </span>
      </div>

      {/* Speed */}
      <div className="bg-dnd-slate border-2 border-gray-600 rounded-lg p-2 flex flex-col items-center">
        <span className="text-xs text-gray-400 uppercase font-bold">Speed</span>
        <span className="text-3xl font-bold text-white font-serif my-auto">30<span className="text-sm font-sans font-normal text-gray-400 ml-1">ft</span></span>
      </div>

      {/* HP Section - Spans full width of grid */}
      <div className="col-span-3 bg-dnd-slate border-2 border-gray-600 rounded-lg p-3 flex flex-col gap-2">
         <div className="flex justify-between items-end border-b border-gray-600 pb-2">
            <div className="flex flex-col">
                <span className="text-xs text-gray-400 uppercase font-bold">Hit Point Maximum</span>
                <div className="flex items-center gap-2">
                     <span className="text-sm text-gray-300">Auto: {calculateMaxHP(data.class, data.level, data.abilities.CON, null)}</span>
                     <span className="text-xs text-gray-500">|</span>
                     <label className="text-xs text-gray-400">Override:</label>
                     <input 
                        type="number" 
                        className="w-16 bg-dnd-dark border border-gray-500 rounded px-1 text-sm"
                        value={data.hpMaxOverride ?? ''}
                        onChange={(e) => {
                             const val = e.target.value === '' ? null : parseInt(e.target.value);
                             onChange('hpMaxOverride', val);
                        }}
                     />
                </div>
            </div>
            <div className="text-right">
                <span className="text-xs text-gray-400 uppercase font-bold block">Proficiency Bonus</span>
                <span className="text-xl font-bold text-dnd-gold">+{profBonus}</span>
            </div>
         </div>

         <div className="flex items-center justify-center py-2">
            <input 
                type="number" 
                className="bg-transparent text-5xl font-bold text-center w-full focus:outline-none text-white font-serif"
                value={data.hpCurrent}
                onChange={(e) => onChange('hpCurrent', parseInt(e.target.value) || 0)}
            />
            <span className="text-2xl text-gray-500 font-serif"> / {maxHP}</span>
         </div>
         <span className="text-xs text-center text-gray-400 uppercase font-bold">Current Hit Points</span>
      </div>

       {/* Passive Perception */}
       <div className="col-span-3 bg-dnd-slate border border-gray-600 rounded-full py-2 px-4 flex justify-between items-center">
            <span className="text-sm text-gray-300 font-bold uppercase">Passive Wisdom (Perception)</span>
            <span className="text-xl font-bold text-white">{passivePerception}</span>
       </div>
    </div>
  );
};

import React, { useState } from 'react';
import { CharacterData } from '../types';
import { generateBackstory } from '../services/geminiService';

interface BackstoryProps {
  data: CharacterData;
  onUpdate: (story: string) => void;
}

export const BackstoryGenerator: React.FC<BackstoryProps> = ({ data, onUpdate }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    setLoading(true);
    setError(null);
    try {
      const story = await generateBackstory(data);
      onUpdate(story);
    } catch (err) {
      setError("Failed to generate backstory.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-dnd-slate rounded-lg border border-gray-700 p-4 h-full flex flex-col">
      <div className="flex justify-between items-center mb-3 border-b border-gray-600 pb-2">
        <h3 className="text-dnd-gold font-serif text-xl">Backstory & Traits</h3>
        <button
          onClick={handleGenerate}
          disabled={loading}
          className={`px-3 py-1 text-sm rounded font-bold transition-all ${
            loading 
            ? 'bg-gray-600 cursor-not-allowed text-gray-400' 
            : 'bg-dnd-gold text-black hover:bg-yellow-500 shadow-md hover:shadow-lg'
          }`}
        >
          {loading ? 'Consulting the Sages...' : 'Generate with AI'}
        </button>
      </div>

      {error && <p className="text-red-400 text-sm mb-2">{error}</p>}

      <textarea
        className="flex-1 w-full bg-dnd-dark border border-gray-600 rounded p-3 text-gray-300 focus:border-dnd-gold outline-none resize-none font-serif leading-relaxed"
        placeholder="Character backstory will appear here, or type your own..."
        value={data.backstory}
        onChange={(e) => onUpdate(e.target.value)}
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { AbilityScore } from './components/AbilityScore';
import { SkillList } from './components/SkillList';
import { Vitals } from './components/Vitals';
import { BackstoryGenerator } from './components/BackstoryGenerator';
import { CharacterData, INITIAL_CHARACTER, AbilityName } from './types';
import { calculateProficiencyBonus } from './utils/dndCalculations';
import { ABILITIES } from './constants';

export default function App() {
  const [character, setCharacter] = useState<CharacterData>(INITIAL_CHARACTER);

  // Load from local storage on mount (optional but nice UX)
  useEffect(() => {
    const saved = localStorage.getItem('dnd-character-sheet');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Rehydrate Sets
        parsed.proficiencies = new Set(parsed.proficiencies);
        parsed.expertises = new Set(parsed.expertises);
        setCharacter(parsed);
      } catch (e) {
        console.error("Failed to load saved character", e);
      }
    }
  }, []);

  // Save to local storage on change
  useEffect(() => {
    const toSave = {
      ...character,
      proficiencies: Array.from(character.proficiencies),
      expertises: Array.from(character.expertises)
    };
    localStorage.setItem('dnd-character-sheet', JSON.stringify(toSave));
  }, [character]);

  const updateField = (field: keyof CharacterData, value: any) => {
    setCharacter(prev => ({ ...prev, [field]: value }));
  };

  const updateAbility = (ability: AbilityName, val: number) => {
    setCharacter(prev => ({
      ...prev,
      abilities: { ...prev.abilities, [ability]: val }
    }));
  };

  const toggleProficiency = (key: string) => {
    setCharacter(prev => {
      const newProfs = new Set(prev.proficiencies);
      if (newProfs.has(key)) {
        newProfs.delete(key);
      } else {
        newProfs.add(key);
      }
      return { ...prev, proficiencies: newProfs };
    });
  };

  const profBonus = calculateProficiencyBonus(character.level);

  return (
    <div className="container mx-auto max-w-6xl p-4 md:p-8">
      <header className="mb-8 text-center">
        <h1 className="text-4xl md:text-5xl font-serif text-dnd-gold font-bold drop-shadow-md">
           Adventurer's Codex
        </h1>
        <p className="text-gray-400 mt-2">5th Edition Character Sheet & Generator</p>
      </header>

      <Header data={character} onChange={updateField} />

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

        {/* Left Column: Abilities & Vitals */}
        <div className="lg:col-span-4 space-y-6">
            <div className="grid grid-cols-3 gap-2">
                {ABILITIES.map(ability => (
                    <AbilityScore
                        key={ability}
                        ability={ability}
                        score={character.abilities[ability]}
                        onChange={(val) => updateAbility(ability, val)}
                        savingThrowProficient={character.proficiencies.has(ability)}
                        onToggleSave={() => toggleProficiency(ability)}
                        profBonus={profBonus}
                    />
                ))}
            </div>

            <Vitals 
                data={character} 
                onChange={updateField} 
                profBonus={profBonus}
            />
        </div>

        {/* Center Column: Skills */}
        <div className="lg:col-span-4">
            <SkillList
                abilities={character.abilities}
                profBonus={profBonus}
                proficiencies={character.proficiencies}
                expertises={character.expertises}
                onToggleProficiency={toggleProficiency}
            />
        </div>

        {/* Right Column: Backstory & Features */}
        <div className="lg:col-span-4 flex flex-col gap-6">
            <div className="flex-1 min-h-[400px]">
                 <BackstoryGenerator 
                    data={character}
                    onUpdate={(story) => updateField('backstory', story)}
                 />
            </div>

            {/* Additional simple notes section */}
            <div className="bg-dnd-slate rounded-lg border border-gray-700 p-4 h-64 flex flex-col">
