import React from 'react';
import { AbilityName, CharacterData } from '../types';
import { calculateModifier, formatModifier } from '../utils/dndCalculations';
import { SKILLS } from '../constants';

interface AbilityScoreRowProps {
  ability: AbilityName;
  score: number;
  profBonus: number;
  proficiencies: Set<string>;
  onChangeScore: (val: number) => void;
  onToggleProficiency: (key: string) => void;
}

export const AbilityScoreRow: React.FC<AbilityScoreRowProps> = ({
  ability,
  score,
  profBonus,
  proficiencies,
  onChangeScore,
  onToggleProficiency,
}) => {
  const mod = calculateModifier(score);
  const saveMod = mod + (proficiencies.has(ability) ? profBonus : 0);

  // Filter skills for this ability
  const abilitySkills = SKILLS.filter(s => s.ability === ability);

  return (
    <div className="flex flex-row items-center gap-4 mb-4">
      {/* Left: Ability Score Box */}
      <div className="flex flex-col items-center justify-center w-24 relative">
        <div className="border-2 border-gray-400 rounded-xl w-24 h-28 flex flex-col items-center bg-white relative shadow-sm">

           {/* Label inside top */}
           <span className="text-[10px] uppercase font-bold text-gray-500 mt-1">{ability}</span>

           {/* Modifier (Top, geometric shape) */}
           <div className="relative z-10 -mt-1 mb-1">
             <div className="w-16 h-10 bg-white border border-gray-400 flex items-center justify-center clip-trapezoid shadow-sm">
                <span className="text-xl font-bold font-serif">{formatModifier(mod)}</span>
             </div>
           </div>

           {/* Score (Bottom, big number) */}
           <input
              type="number"
              value={score}
              onChange={(e) => onChangeScore(parseInt(e.target.value) || 0)}
              className="text-3xl font-bold text-center w-full bg-transparent outline-none font-serif mb-2"
           />
        </div>

        {/* Helper Badge for Score */}
        <div className="bg-white px-2 py-0.5 rounded-full border border-gray-300 text-[10px] -mt-3 z-20 font-bold text-gray-500 uppercase">
          Score
        </div>
      </div>

      {/* Right: Skills & Save */}
      <div className="flex-1 flex flex-col gap-1">
         {/* Saving Throw Row */}
         <div className="flex items-center text-sm mb-1">
            <input 
                type="checkbox" 
                checked={proficiencies.has(ability)} 
                onChange={() => onToggleProficiency(ability)}
                className="w-4 h-4 rounded-full border-gray-400 mr-2 accent-black"
            />
            <span className="w-6 text-center border-b border-gray-300 mr-2 font-mono">{formatModifier(saveMod)}</span>
            <span className="font-bold text-gray-700">Saving Throws</span>
         </div>

         {/* Skill Rows */}
         {abilitySkills.map(skill => {
            let skillMod = mod;
            if (proficiencies.has(skill.name)) skillMod += profBonus;

            return (
                <div key={skill.name} className="flex items-center text-sm">
                    <input 
                        type="checkbox" 
                        checked={proficiencies.has(skill.name)} 
                        onChange={() => onToggleProficiency(skill.name)}
                        className="w-4 h-4 rounded-full border-gray-400 mr-2 accent-black"
                    />
                    <span className="w-6 text-center border-b border-gray-300 mr-2 font-mono text-gray-600">
                        {formatModifier(skillMod)}
                    </span>
                    <span className="text-gray-800">{skill.name}</span>
                </div>
            )
         })}
      </div>
    </div>
  );
};

import React from 'react';
import { CharacterData } from '../types';
import { calculateModifier, calculateMaxHP } from '../utils/dndCalculations';

interface VitalsProps {
  data: CharacterData;
  onChange: (field: keyof CharacterData, value: any) => void;
  profBonus: number;
}

export const Vitals: React.FC<VitalsProps> = ({ data, onChange }) => {
  const dexMod = calculateModifier(data.abilities.DEX);
  const calculatedAC = 10 + dexMod;
  const finalAC = data.acOverride !== null ? data.acOverride : calculatedAC;
  const maxHP = calculateMaxHP(data.class, data.level, data.abilities.CON, data.hpMaxOverride);
  const initiative = data.initiativeOverride !== null ? data.initiativeOverride : dexMod;
  const initiativeDisplay = initiative >= 0 ? `+${initiative}` : `${initiative}`;

  const updateDeathSave = (type: 'success' | 'failures', index: number) => {
    const arr = [...data.deathSaves[type]];
    arr[index] = !arr[index];
    onChange('deathSaves', { ...data.deathSaves, [type]: arr });
  };

  return (
    <div className="bg-gray-100 p-3 rounded-lg border border-gray-300 shadow-sm">
      {/* Top Row: AC, Init, Speed */}
      <div className="grid grid-cols-3 gap-3 mb-3">
        {/* AC */}
        <div className="border-2 border-gray-400 bg-white rounded p-2 flex flex-col items-center relative group">
          <div className="absolute -top-3 bg-white px-1 text-[10px] font-bold text-gray-500 uppercase">Armor Class</div>
          <span className="text-3xl font-bold font-serif my-1">{finalAC}</span>
          <input 
             type="number" 
             className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
             onChange={(e) => onChange('acOverride', e.target.value ? parseInt(e.target.value) : null)}
             title="Click to override AC"
          />
        </div>

        {/* Initiative */}
        <div className="border-2 border-gray-400 bg-white rounded p-2 flex flex-col items-center relative">
          <div className="absolute -top-3 bg-white px-1 text-[10px] font-bold text-gray-500 uppercase">Initiative</div>
          <span className="text-3xl font-bold font-serif my-1">{initiativeDisplay}</span>
        </div>

        {/* Speed */}
        <div className="border-2 border-gray-400 bg-white rounded p-2 flex flex-col items-center relative">
          <div className="absolute -top-3 bg-white px-1 text-[10px] font-bold text-gray-500 uppercase">Speed</div>
          <input 
             type="text"
             className="text-3xl font-bold font-serif my-1 text-center w-full outline-none"
             value={data.speed}
             onChange={(e) => onChange('speed', e.target.value)}
          />
        </div>
      </div>

      {/* HP Section */}
      <div className="border border-gray-300 bg-white rounded p-2 mb-3">
         <div className="flex justify-between items-center border-b border-gray-200 pb-1 mb-2">
            <span className="text-[10px] font-bold text-gray-500 uppercase">Hit Point Maximum</span>
            <div className="flex items-center gap-2">
                 <span className="text-xs text-gray-400">Calc: {calculateMaxHP(data.class, data.level, data.abilities.CON, null)}</span>
                 <input 
                    type="number" 
                    placeholder="Override"
                    className="w-16 border-b border-gray-300 text-right text-xs"
                    value={data.hpMaxOverride ?? ''}
                    onChange={(e) => onChange('hpMaxOverride', e.target.value ? parseInt(e.target.value) : null)}
                 />
            </div>
            <span className="font-bold text-sm text-gray-700">{maxHP}</span>
         </div>
         <div className="flex gap-2">
            <input 
                type="number" 
                className="flex-1 text-4xl font-serif text-center outline-none"
                value={data.hpCurrent}
                onChange={(e) => onChange('hpCurrent', parseInt(e.target.value) || 0)}
                placeholder="Current"
            />
         </div>
         <div className="text-center text-[10px] text-gray-500 uppercase font-bold">Current Hit Points</div>
      </div>

       {/* Temp HP */}
       <div className="border border-gray-300 bg-white rounded p-2 mb-3">
         <input 
            type="text"
            className="w-full text-center text-xl font-serif outline-none"
            value={data.hpTemp}
            onChange={(e) => onChange('hpTemp', e.target.value)}
            placeholder="--"
         />
         <div className="text-center text-[10px] text-gray-500 uppercase font-bold mt-1">Temporary Hit Points</div>
       </div>

       {/* HD and Death Saves */}
       <div className="grid grid-cols-2 gap-3">
          {/* Hit Dice */}
          <div className="border border-gray-300 bg-white rounded p-2">
             <div className="flex justify-between text-[10px] text-gray-500 uppercase font-bold mb-1">
                <span>Hit Dice</span>
                <span>Total: {data.level}</span>
             </div>
             <div className="flex items-center gap-1">
                 <input 
                    type="text" 
                    className="w-1/2 text-center border-b border-gray-200"
                    placeholder="Total"
                    value={data.hitDiceTotal}
                    onChange={(e) => onChange('hitDiceTotal', e.target.value)}
                 />
                 <input 
                    type="text" 
                    className="w-1/2 text-center border-b border-gray-200"
                    placeholder="Used"
                    value={data.hitDiceUsed}
                    onChange={(e) => onChange('hitDiceUsed', e.target.value)}
                 />
             </div>
          </div>

          {/* Death Saves */}
          <div className="border border-gray-300 bg-white rounded p-2">
             <div className="text-[10px] text-gray-500 uppercase font-bold mb-1 text-center">Death Saves</div>

             <div className="flex justify-between items-center text-xs mb-1">
                <span className="w-12 text-right mr-1">Successes</span>
                <div className="flex gap-1">
                    {[0, 1, 2].map(i => (
                        <input key={i} type="checkbox" checked={data.deathSaves.success[i]} onChange={() => updateDeathSave('success', i)} className="accent-green-600"/>
                    ))}
                </div>
             </div>
             <div className="flex justify-between items-center text-xs">
                <span className="w-12 text-right mr-1">Failures</span>
                <div className="flex gap-1">
                    {[0, 1, 2].map(i => (
                        <input key={i} type="checkbox" checked={data.deathSaves.failures[i]} onChange={() => updateDeathSave('failures', i)} className="accent-red-600"/>
                    ))}
                </div>
             </div>
          </div>
       </div>

    </div>
  );
};

