import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { AbilityScoreRow } from './components/AbilityScore';
import { Vitals } from './components/Vitals';
import { Personality } from './components/Personality';
import { Attacks } from './components/Attacks';
import { InventoryGrid } from './components/InventoryGrid';
import { SpellList } from './components/SpellList';
import { BackstoryGenerator } from './components/BackstoryGenerator'; // Kept for functionality, but moved
import { CharacterData, INITIAL_CHARACTER, AbilityName } from './types';
import { calculateProficiencyBonus, calculateModifier } from './utils/dndCalculations';
import { ABILITIES } from './constants';

export default function App() {
  const [character, setCharacter] = useState<CharacterData>(INITIAL_CHARACTER);

  useEffect(() => {
    const saved = localStorage.getItem('dnd-character-sheet');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        parsed.proficiencies = new Set(parsed.proficiencies);
        parsed.expertises = new Set(parsed.expertises);
        // Ensure defaults for new fields if loading old data
        if (!parsed.attacks) parsed.attacks = INITIAL_CHARACTER.attacks;
        if (!parsed.currency) parsed.currency = INITIAL_CHARACTER.currency;
        if (!parsed.proficienciesText) parsed.proficienciesText = INITIAL_CHARACTER.proficienciesText;
        if (!parsed.status) parsed.status = INITIAL_CHARACTER.status;
        if (!parsed.deathSaves) parsed.deathSaves = INITIAL_CHARACTER.deathSaves;

        setCharacter(parsed);
      } catch (e) {
        console.error("Failed to load saved character", e);
      }
    }
  }, []);

  useEffect(() => {
    const toSave = {
      ...character,
      proficiencies: Array.from(character.proficiencies),
      expertises: Array.from(character.expertises)
    };
    localStorage.setItem('dnd-character-sheet', JSON.stringify(toSave));
  }, [character]);

  const updateField = (field: keyof CharacterData, value: any) => {
    setCharacter(prev => ({ ...prev, [field]: value }));
  };

  const updateAbility = (ability: AbilityName, val: number) => {
    setCharacter(prev => ({
      ...prev,
      abilities: { ...prev.abilities, [ability]: val }
    }));
  };

  const toggleProficiency = (key: string) => {
    setCharacter(prev => {
      const newProfs = new Set(prev.proficiencies);
      if (newProfs.has(key)) {
        newProfs.delete(key);
      } else {
        newProfs.add(key);
      }
      return { ...prev, proficiencies: newProfs };
    });
  };

  const profBonus = calculateProficiencyBonus(character.level);

  return (
    <div className="container mx-auto max-w-5xl p-4 md:p-8">
      <header className="mb-6 flex justify-between items-end border-b-2 border-dnd-red pb-2">
        <h1 className="text-4xl font-serif text-dnd-red font-bold">
           Dungeons & Dragons
        </h1>
        <div className="text-right">
             <div className="text-xs text-gray-500">Proficiency Bonus</div>
             <div className="text-xl font-bold border border-gray-300 rounded px-3 bg-white inline-block">+{profBonus}</div>
             <div className="text-xs text-gray-500 mt-1">Passive Wisdom (Perception)</div>
             <div className="font-bold text-gray-700">
                {10 + calculateModifier(character.abilities.WIS) + (character.proficiencies.has('Perception') ? profBonus : 0)}
             </div>
        </div>
      </header>

      <Header data={character} onChange={updateField} />

      {/* Main Sheet Body */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

        {/* Left Column: Abilities + Skills (Takes up roughly 1/3) */}
        <div className="lg:col-span-4 bg-gray-50 p-2 rounded-lg border border-gray-200">
            {ABILITIES.map(ability => (
                <AbilityScoreRow
                    key={ability}
                    ability={ability}
                    score={character.abilities[ability]}
                    profBonus={profBonus}
                    proficiencies={character.proficiencies}
                    onChangeScore={(val) => updateAbility(ability, val)}
                    onToggleProficiency={toggleProficiency}
                />
            ))}
        </div>

        {/* Right Column: Combat, Personality, Attacks (Takes up 2/3) */}
        <div className="lg:col-span-8 flex flex-col gap-4">

            {/* Top Right: Combat Stats & Personality */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 h-auto">
                {/* Combat Stats */}
                <Vitals 
                    data={character} 
                    onChange={updateField} 
                    profBonus={profBonus}
                />

                {/* Personality & Background */}
                <Personality 
                    data={character} 
                    onChange={updateField}
                />
            </div>

            {/* Middle Right: Attacks */}
            <div className="flex-1 min-h-[300px]">
                <Attacks 
                    attacks={character.attacks} 
                    onUpdate={(atks) => updateField('attacks', atks)}
                />
            </div>

            {/* Backstory Generator (Compact) */}
            <div className="mt-2">
                 <BackstoryGenerator 
                    data={character}
                    onUpdate={(story) => updateField('backstory', story)}
                 />
            </div>

        </div>
      </div>

      {/* Bottom Section: Inventory & Spells */}
      <InventoryGrid data={character} onChange={updateField} />

      <SpellList spells={character.spells} onChange={(val) => updateField('spells', val)} />

      <footer className="mt-12 text-center text-gray-400 text-xs">
        <p>&copy; {new Date().getFullYear()} D&D Auto-Sheet. Not affiliated with Wizards of the Coast.</p>
      </footer>
    </div>
  );
}

export type AbilityName = 'STR' | 'DEX' | 'CON' | 'INT' | 'WIS' | 'CHA';

export interface AbilityScores {
  STR: number;
  DEX: number;
  CON: number;
  INT: number;
  WIS: number;
  CHA: number;
}

export interface SkillDefinition {
  name: string;
  ability: AbilityName;
}

export interface Attack {
  id: string;
  name: string;
  bonus: string;
  damage: string;
  type: string;
  notes: string;
}

export interface Currency {
  cp: string;
  sp: string;
  ep: string;
  gp: string;
  pp: string;
}

export interface CharacterData {
  name: string;
  race: string;
  subrace: string;
  class: string;
  subclass: string;
  level: number;
  alignment: string;
  background: string;
  playerName: string;
  experience: string;
  bodyType: string;

  // Stats
  abilities: AbilityScores;
  inspiration: boolean;

  // Proficiencies (Set of strings matching skill names or ability names for saves)
  proficiencies: Set<string>;
  expertises: Set<string>; // For skills with double proficiency

  // Combat Stats
  acOverride: number | null;
  armorBase: number; // Base armor value (default 10)
  armorBonus: number; // Shield or magic item bonus
  initiativeOverride: number | null;
  speed: string;
  hpCurrent: number;
  hpMaxOverride: number | null;
  hpTemp: string;
  hitDiceTotal: string;
  hitDiceUsed: string;

  deathSaves: {
    success: [boolean, boolean, boolean];
    failures: [boolean, boolean, boolean];
  };

  // Personality
  traits: string;
  ideals: string;
  bonds: string;
  flaws: string;

  // Attacks
  attacks: Attack[];

  // Inventory / Bottom Section
  proficienciesText: {
    armor: string;
    weapons: string;
    tools: string;
    languages: string;
    other: string;
  };
  currency: Currency;
  status: {
    concentrating: boolean;
    conditions: string;
    other: string;
  };

  // Features & Traits (Right column bottom)
  features: string;

  // Spells
  spells: string;

  // AI Backstory (Legacy/Hidden or repurposed)
  backstory: string;
}

