import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { AbilityScoreRow } from './components/AbilityScore';
import { Vitals } from './components/Vitals';
import { Personality } from './components/Personality';
import { Attacks } from './components/Attacks';
import { ProficienciesBox } from './components/ProficienciesBox';
import { Equipment } from './components/Equipment';
import { FeaturesBox } from './components/FeaturesBox';
import { SpellList } from './components/SpellList';
import { BackstoryGenerator } from './components/BackstoryGenerator';
import { SpellSheet } from './components/SpellSheet';
import { CharacterData, INITIAL_CHARACTER, AbilityName } from './types';
import { calculateProficiencyBonus, calculateModifier } from './utils/dndCalculations';
import { ABILITIES } from './constants';

export default function App() {
  const [character, setCharacter] = useState<CharacterData>(INITIAL_CHARACTER);
  const [activePage, setActivePage] = useState<'main' | 'spells' | 'notes'>('main');

  useEffect(() => {
    const saved = localStorage.getItem('dnd-character-sheet');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        parsed.proficiencies = new Set(parsed.proficiencies);
        parsed.expertises = new Set(parsed.expertises);

        // Ensure structure defaults
        const defaults = INITIAL_CHARACTER;
        if (!parsed.attacks) parsed.attacks = defaults.attacks;
        if (!parsed.currency) parsed.currency = defaults.currency;
        if (!parsed.proficienciesText) parsed.proficienciesText = defaults.proficienciesText;
        if (!parsed.status) parsed.status = defaults.status;
        if (!parsed.deathSaves) parsed.deathSaves = defaults.deathSaves;
        if (parsed.armorBase === undefined) parsed.armorBase = 10;
        if (parsed.armorBonus === undefined) parsed.armorBonus = 0;
        if (parsed.inspiration === undefined) parsed.inspiration = false;
        if (!parsed.spellcasting) parsed.spellcasting = defaults.spellcasting;
        if (!parsed.spellsByLevel) parsed.spellsByLevel = defaults.spellsByLevel;

        setCharacter(parsed);
      } catch (e) {
        console.error("Failed to load saved character", e);
      }
    }
  }, []);

  useEffect(() => {
    const toSave = {
      ...character,
      proficiencies: Array.from(character.proficiencies),
      expertises: Array.from(character.expertises)
    };
    localStorage.setItem('dnd-character-sheet', JSON.stringify(toSave));
  }, [character]);

  const updateField = (field: keyof CharacterData, value: any) => {
    setCharacter(prev => ({ ...prev, [field]: value }));
  };

  const updateAbility = (ability: AbilityName, val: number) => {
    setCharacter(prev => ({
      ...prev,
      abilities: { ...prev.abilities, [ability]: val }
    }));
  };

  const toggleProficiency = (key: string) => {
    setCharacter(prev => {
      const newProfs = new Set(prev.proficiencies);
      if (newProfs.has(key)) {
        newProfs.delete(key);
      } else {
        newProfs.add(key);
      }
      return { ...prev, proficiencies: newProfs };
    });
  };

  const profBonus = calculateProficiencyBonus(character.level);
  const passivePerception = 10 + calculateModifier(character.abilities.WIS) + (character.proficiencies.has('Perception') ? profBonus : 0);

  return (
    <div className="container mx-auto max-w-7xl p-4 min-h-screen flex flex-col">

      {/* GLOBAL HEADER */}
      <Header data={character} onChange={updateField} />

      {/* NAVIGATION TABS */}
      <div className="flex gap-2 mb-6 border-b border-gray-300 pb-1">
        <button 
          onClick={() => setActivePage('main')}
          className={`px-4 py-2 font-bold uppercase text-sm rounded-t-lg transition-colors ${activePage === 'main' ? 'bg-dnd-red text-white' : 'bg-gray-200 text-gray-600 hover:bg-gray-300'}`}
        >
          Main Sheet
        </button>
        <button 
          onClick={() => setActivePage('spells')}
          className={`px-4 py-2 font-bold uppercase text-sm rounded-t-lg transition-colors ${activePage === 'spells' ? 'bg-dnd-red text-white' : 'bg-gray-200 text-gray-600 hover:bg-gray-300'}`}
        >
          Spellcasting
        </button>
        <button 
          onClick={() => setActivePage('notes')}
          className={`px-4 py-2 font-bold uppercase text-sm rounded-t-lg transition-colors ${activePage === 'notes' ? 'bg-dnd-red text-white' : 'bg-gray-200 text-gray-600 hover:bg-gray-300'}`}
        >
          Backstory & Notes
        </button>
      </div>

      {/* PAGE 1: MAIN SHEET */}
      {activePage === 'main' && (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 animate-in fade-in duration-300">
          {/* LEFT COLUMN (3/12) */}
          <div className="lg:col-span-3 flex flex-col gap-4">
               {/* Passive Block */}
               <div className="flex flex-col gap-2">
                  <div className="flex items-center justify-between bg-white border border-gray-300 rounded-full px-3 py-1 shadow-sm">
                      <span className="text-[10px] uppercase font-bold text-gray-500">Inspiration</span>
                      <input 
                          type="checkbox" 
                          checked={character.inspiration} 
                          onChange={(e) => updateField('inspiration', e.target.checked)}
                          className="w-5 h-5 accent-dnd-red"
                      />
                  </div>
                  <div className="flex items-center justify-between bg-white border border-gray-300 rounded px-3 py-1 shadow-sm">
                      <span className="text-[10px] uppercase font-bold text-gray-500">Proficiency</span>
                      <span className="font-bold text-lg">+{profBonus}</span>
                  </div>
                  <div className="flex items-center justify-between bg-white border border-gray-300 rounded px-3 py-1 shadow-sm">
                      <span className="text-[10px] uppercase font-bold text-gray-500">Passive Perception</span>
                      <span className="font-bold text-lg">{passivePerception}</span>
                  </div>
               </div>

               <div className="bg-gray-50 p-2 rounded-lg border border-gray-200">
                  {ABILITIES.map(ability => (
                      <AbilityScoreRow
                          key={ability}
                          ability={ability}
                          score={character.abilities[ability]}
                          profBonus={profBonus}
                          proficiencies={character.proficiencies}
                          onChangeScore={(val) => updateAbility(ability, val)}
                          onToggleProficiency={toggleProficiency}
                      />
                  ))}
               </div>

               <ProficienciesBox data={character} onChange={updateField} />
          </div>

          {/* CENTER COLUMN (5/12) */}
          <div className="lg:col-span-5 flex flex-col gap-4">
              <Vitals 
                  data={character} 
                  onChange={updateField} 
                  profBonus={profBonus}
              />
              <div className="flex-1 min-h-[300px]">
                  <Attacks 
                      attacks={character.attacks} 
                      onUpdate={(atks) => updateField('attacks', atks)}
                  />
              </div>
              <div className="h-64">
                  <Equipment data={character} onChange={updateField} />
              </div>
          </div>

          {/* RIGHT COLUMN (4/12) */}
          <div className="lg:col-span-4 flex flex-col gap-4">
               <div className="flex-1 min-h-[400px]">
                   <Personality data={character} onChange={updateField} />
               </div>
               <div className="flex-1 min-h-[200px]">
                   <FeaturesBox data={character} onChange={(val) => updateField('features', val)} />
               </div>
          </div>

          {/* Quick Spell View (Optional, kept from previous version) */}
          <div className="col-span-12">
             <SpellList spells={character.spells} onChange={(val) => updateField('spells', val)} />
          </div>
        </div>
      )}

      {/* PAGE 2: SPELLCASTING */}
      {activePage === 'spells' && (
         <div className="animate-in fade-in duration-300">
            <SpellSheet data={character} onChange={updateField} profBonus={profBonus} />
         </div>
      )}

      {/* PAGE 3: NOTES */}
      {activePage === 'notes' && (
        <div className="animate-in fade-in duration-300 max-w-4xl mx-auto w-full">
           <BackstoryGenerator 
              data={character}
              onUpdate={(story) => updateField('backstory', story)}
           />
        </div>
      )}

      <footer className="mt-auto pt-12 text-center text-gray-400 text-xs pb-4">
        <p>&copy; {new Date().getFullYear()} D&D Auto-Sheet. Not affiliated with Wizards of the Coast.</p>
      </footer>
    </div>
  );
}

