import React from 'react';
import { CharacterData } from '../types';
import { ABILITIES } from '../constants';
import { calculateSpellSaveDC, calculateSpellAttackBonus, formatModifier } from '../utils/dndCalculations';

interface SpellSheetProps {
  data: CharacterData;
  onChange: (field: keyof CharacterData, value: any) => void;
  profBonus: number;
}

interface SpellBlockProps {
    level: number;
    data: CharacterData;
    onUpdateLevel: (level: number, field: 'totalSlots' | 'expendedSlots', value: string) => void;
    onUpdateSpell: (level: number, index: number, field: 'name' | 'prepared', value: any) => void;
}

const SpellBlock: React.FC<SpellBlockProps> = ({ level, data, onUpdateLevel, onUpdateSpell }) => {
    const levelData = data.spellsByLevel[level];
    const isCantrip = level === 0;

    return (
      <div className="bg-white border-2 border-gray-300 rounded mb-4 overflow-hidden">
        {/* Header */}
        <div className="bg-gray-100 border-b border-gray-300 p-1 flex items-center justify-between">
            <div className="flex items-center gap-2">
                 <div className="bg-white border border-gray-400 rounded-full w-8 h-8 flex items-center justify-center font-bold text-lg font-serif">
                     {level}
                 </div>
                 <span className="text-[10px] uppercase font-bold text-gray-500">
                     {isCantrip ? "Cantrips" : "Spell Level"}
                 </span>
            </div>
            {!isCantrip && (
                <div className="flex gap-2 text-xs">
                    <div className="flex flex-col items-center bg-white border border-gray-300 rounded px-2 py-0.5">
                        <span className="text-[8px] uppercase text-gray-400">Slots Total</span>
                        <input 
                            type="text" 
                            className="w-8 text-center font-bold outline-none"
                            value={levelData.totalSlots}
                            onChange={(e) => onUpdateLevel(level, 'totalSlots', e.target.value)}
                        />
                    </div>
                    <div className="flex flex-col items-center bg-white border border-gray-300 rounded px-2 py-0.5">
                         <span className="text-[8px] uppercase text-gray-400">Expended</span>
                        <input 
                            type="text" 
                            className="w-8 text-center font-bold outline-none"
                            value={levelData.expendedSlots}
                            onChange={(e) => onUpdateLevel(level, 'expendedSlots', e.target.value)}
                        />
                    </div>
                </div>
            )}
        </div>

        {/* Spells List */}
        <div className="p-2 space-y-1">
            {levelData.spells.map((spell, idx) => (
                <div key={idx} className="flex items-center gap-2 border-b border-gray-100 last:border-0 pb-1">
                    {!isCantrip && (
                        <input 
                            type="checkbox" 
                            className="w-4 h-4 rounded-full border-gray-300 accent-dnd-red"
                            checked={spell.prepared}
                            onChange={(e) => onUpdateSpell(level, idx, 'prepared', e.target.checked)}
                            title="Prepared"
                        />
                    )}
                    <input 
                        type="text"
                        className="flex-1 bg-transparent outline-none text-sm font-serif"
                        placeholder="Spell Name"
                        value={spell.name}
                        onChange={(e) => onUpdateSpell(level, idx, 'name', e.target.value)}
                    />
                </div>
            ))}
        </div>
      </div>
    );
};

export const SpellSheet: React.FC<SpellSheetProps> = ({ data, onChange, profBonus }) => {
  const updateSpellcasting = (field: keyof typeof data.spellcasting, value: any) => {
    onChange('spellcasting', { ...data.spellcasting, [field]: value });
  };

  const updateSpellLevel = (level: number, field: 'totalSlots' | 'expendedSlots', value: string) => {
    const newSpellsByLevel = { ...data.spellsByLevel };
    newSpellsByLevel[level] = { ...newSpellsByLevel[level], [field]: value };
    onChange('spellsByLevel', newSpellsByLevel);
  };

  const updateSpell = (level: number, index: number, field: 'name' | 'prepared', value: any) => {
    const newSpellsByLevel = { ...data.spellsByLevel };
    const newSpells = [...newSpellsByLevel[level].spells];
    newSpells[index] = { ...newSpells[index], [field]: value };
    newSpellsByLevel[level] = { ...newSpellsByLevel[level], spells: newSpells };
    onChange('spellsByLevel', newSpellsByLevel);
  };

  // Calculations
  const abilityScore = data.abilities[data.spellcasting.ability] || 10;
  const saveDC = calculateSpellSaveDC(abilityScore, profBonus);
  const attackBonus = calculateSpellAttackBonus(abilityScore, profBonus);

  return (
    <div className="space-y-6">
      {/* Top Bar: Header Info */}
      <div className="bg-white border border-gray-300 rounded-lg p-4 shadow-sm">
         <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
             <div className="flex flex-col">
                 <label className="text-[10px] uppercase font-bold text-gray-500">Spellcasting Class</label>
                 <input 
                    type="text" 
                    className="border-b border-gray-300 py-1 font-serif text-lg outline-none"
                    value={data.spellcasting.class}
                    onChange={(e) => updateSpellcasting('class', e.target.value)}
                    placeholder={data.class}
                 />
             </div>

             <div className="flex flex-col">
                 <label className="text-[10px] uppercase font-bold text-gray-500">Spellcasting Ability</label>
                 <select 
                    className="border-b border-gray-300 py-1 font-serif text-lg outline-none bg-transparent"
                    value={data.spellcasting.ability}
                    onChange={(e) => updateSpellcasting('ability', e.target.value)}
                 >
                     {ABILITIES.map(a => <option key={a} value={a}>{a}</option>)}
                 </select>
             </div>

             <div className="flex flex-col items-center border border-gray-300 rounded p-1 bg-gray-50">
                 <label className="text-[10px] uppercase font-bold text-gray-500">Spell Save DC</label>
                 <div className="flex items-center gap-2">
                    <span className="text-2xl font-bold font-serif">{saveDC}</span>
                    <input 
                        type="text" 
                        className="w-10 text-center text-xs border-b border-gray-300 bg-transparent outline-none" 
                        placeholder="Ovr"
                        value={data.spellcasting.saveDCOverride}
                        onChange={(e) => updateSpellcasting('saveDCOverride', e.target.value)}
                    />
                 </div>
             </div>

             <div className="flex flex-col items-center border border-gray-300 rounded p-1 bg-gray-50">
                 <label className="text-[10px] uppercase font-bold text-gray-500">Spell Attack Bonus</label>
                  <div className="flex items-center gap-2">
                    <span className="text-2xl font-bold font-serif">{formatModifier(attackBonus)}</span>
                    <input 
                        type="text" 
                        className="w-10 text-center text-xs border-b border-gray-300 bg-transparent outline-none" 
                        placeholder="Ovr"
                        value={data.spellcasting.attackBonusOverride}
                        onChange={(e) => updateSpellcasting('attackBonusOverride', e.target.value)}
                    />
                 </div>
             </div>
         </div>
      </div>

      {/* Main Grid: 3 Columns matching PDF Page 3 */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

          {/* Column 1: Cantrips, 1, 2 */}
          <div className="flex flex-col">
              <SpellBlock level={0} data={data} onUpdateLevel={updateSpellLevel} onUpdateSpell={updateSpell} />
              <SpellBlock level={1} data={data} onUpdateLevel={updateSpellLevel} onUpdateSpell={updateSpell} />
              <SpellBlock level={2} data={data} onUpdateLevel={updateSpellLevel} onUpdateSpell={updateSpell} />
          </div>

          {/* Column 2: 3, 4, 5 */}
          <div className="flex flex-col">
              <SpellBlock level={3} data={data} onUpdateLevel={updateSpellLevel} onUpdateSpell={updateSpell} />
              <SpellBlock level={4} data={data} onUpdateLevel={updateSpellLevel} onUpdateSpell={updateSpell} />
              <SpellBlock level={5} data={data} onUpdateLevel={updateSpellLevel} onUpdateSpell={updateSpell} />
          </div>

          {/* Column 3: 6, 7, 8, 9 */}
          <div className="flex flex-col">
              <SpellBlock level={6} data={data} onUpdateLevel={updateSpellLevel} onUpdateSpell={updateSpell} />
              <SpellBlock level={7} data={data} onUpdateLevel={updateSpellLevel} onUpdateSpell={updateSpell} />
              <SpellBlock level={8} data={data} onUpdateLevel={updateSpellLevel} onUpdateSpell={updateSpell} />
              <SpellBlock level={9} data={data} onUpdateLevel={updateSpellLevel} onUpdateSpell={updateSpell} />
          </div>

      </div>
    </div>
  );
};

