export type AbilityName = 'STR' | 'DEX' | 'CON' | 'INT' | 'WIS' | 'CHA';

export interface AbilityScores {
  STR: number;
  DEX: number;
  CON: number;
  INT: number;
  WIS: number;
  CHA: number;
}

export interface SkillDefinition {
  name: string;
  ability: AbilityName;
}

export interface Attack {
  id: string;
  name: string;
  bonus: string;
  damage: string;
  type: string;
  notes: string;
}

export interface Currency {
  cp: string;
  sp: string;
  ep: string;
  gp: string;
  pp: string;
}

export interface CharacterData {
  name: string;
  race: string;
  subrace: string;
  class: string;
  subclass: string;
  level: number;
  alignment: string;
  background: string;
  playerName: string;
  experience: string;
  bodyType: string;

  // Stats
  abilities: AbilityScores;
  inspiration: boolean;

  // Proficiencies (Set of strings matching skill names or ability names for saves)
  proficiencies: Set<string>;
  expertises: Set<string>; // For skills with double proficiency

  // Combat Stats
  acOverride: number | null;
  armorBase: number; // Base armor value (default 10)
  armorBonus: number; // Shield or magic item bonus
  initiativeOverride: number | null;
  speed: string;
  hpCurrent: number;
  hpMaxOverride: number | null;
  hpTemp: string;
  hitDiceTotal: string;
  hitDiceUsed: string;

  deathSaves: {
    success: [boolean, boolean, boolean];
    failures: [boolean, boolean, boolean];
  };

  // Personality
  traits: string;
  ideals: string;
  bonds: string;
  flaws: string;

  // Attacks
  attacks: Attack[];

  // Inventory / Bottom Section
  proficienciesText: {
    armor: string;
    weapons: string;
    tools: string;
    languages: string;
    other: string;
  };
  currency: Currency;
  status: {
    concentrating: boolean;
    conditions: string;
    other: string;
  };

  // Features & Traits (Right column bottom)
  features: string;

  // Spells
  spells: string;

  // AI Backstory (Legacy/Hidden or repurposed)
  backstory: string;
}

