}

export interface Attack {
  id: string;
  name: string;
  bonus: string;
  damage: string;
  type: string;
  notes: string;
}

export interface Currency {
  cp: string;
  sp: string;
  ep: string;
  gp: string;
  pp: string;
}

export interface Spell {
  id: string;
  level: number;
  name: string;
  prepared: boolean;
  time: string;
  range: string;
  components: string; // V, S, M
  duration: string;
