  proficiencies: Set<string>;
  expertises: Set<string>;

  // Combat Stats
  acOverride: number | null;
  armorBase: number;
  armorBonus: number;
  initiativeOverride: number | null;
  speed: string;
  hpCurrent: number;
  hpMaxOverride: number | null;
  hpTemp: string;
  hitDiceTotal: string;
  hitDiceUsed: string;

  deathSaves: {
    success: [boolean, boolean, boolean];
    failures: [boolean, boolean, boolean];
  };

  // Personality
  traits: string;
  ideals: string;
  bonds: string;
  flaws: string;

  // Attacks
  attacks: Attack[];

  // Inventory / Bottom Section
  proficienciesText: {
    armor: string;
    weapons: string;
    tools: string;
    languages: string;
    other: string;
  };
  currency: Currency;
  status: {
    concentrating: boolean;
    conditions: string;
    other: string;
  };

  // Features & Traits
  features: string;

  // Spellcasting
  spellcasting: {
    class: string;
    ability: AbilityName;
    saveDCOverride: string;
    attackBonusOverride: string;
    slots: { [level: number]: SpellSlot }; // 1-9
    spells: Spell[];
  };

  backstory: string;
}

