            <div className="flex gap-2">
                <button 
                    onClick={() => setLanguage('en')} 
                    className={`text-xs font-bold ${language === 'en' ? 'text-dnd-red underline' : 'text-gray-400'}`}
                >EN</button>
                <button 
                    onClick={() => setLanguage('zh')} 
                    className={`text-xs font-bold ${language === 'zh' ? 'text-dnd-red underline' : 'text-gray-400'}`}
