        if (parsed.armorBase === undefined) parsed.armorBase = 10;
        if (parsed.armorBonus === undefined) parsed.armorBonus = 0;
        if (parsed.inspiration === undefined) parsed.inspiration = false;

        if (typeof parsed.spells === 'string' || !parsed.spellcasting) {
            parsed.spellcasting = defaults.spellcasting;
            delete parsed.spells;
        }
        if (!parsed.spellcasting.slots) parsed.spellcasting.slots = defaults.spellcasting.slots;

        setCharacter(parsed);
      } catch (e) {
        console.error("Failed to load saved character", e);
        setCharacter(INITIAL_CHARACTER);
      }
    } else {
        setCharacter(INITIAL_CHARACTER);
    }
  }, [user]);

  // Auto-save logic
  useEffect(() => {
    if (!user) return;

    const toSave = {
      ...character,
      proficiencies: Array.from(character.proficiencies),
      expertises: Array.from(character.expertises)
    };
    localStorage.setItem(`dnd_data_${user.username}`, JSON.stringify(toSave));
  }, [character, user]);

  const updateField = (field: keyof CharacterData, value: any) => {
    setCharacter(prev => ({ ...prev, [field]: value }));
  };

  const updateAbility = (ability: AbilityName, val: number) => {
    setCharacter(prev => ({
      ...prev,
      abilities: { ...prev.abilities, [ability]: val }
    }));
  };

  const toggleProficiency = (key: string) => {
    setCharacter(prev => {
      const newProfs = new Set(prev.proficiencies);
      if (newProfs.has(key)) {
        newProfs.delete(key);
      } else {
        newProfs.add(key);
      }
      return { ...prev, proficiencies: newProfs };
    });
  };

  // Header Actions
  const handleSave = () => {
    if (!user) return;
    const toSave = {
        ...character,
        proficiencies: Array.from(character.proficiencies),
        expertises: Array.from(character.expertises)
    };
    localStorage.setItem(`dnd_data_${user.username}`, JSON.stringify(toSave));
    alert(t('header.saved'));
  };

  const handleDownload = () => {
    const toSave = {
        ...character,
        proficiencies: Array.from(character.proficiencies),
        expertises: Array.from(character.expertises)
    };
    const blob = new Blob([JSON.stringify(toSave, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${character.name || 'character'}_sheet.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const parsed = JSON.parse(event.target?.result as string);

              // Validate/Migrate similar to load
              parsed.proficiencies = new Set(parsed.proficiencies);
              parsed.expertises = new Set(parsed.expertises);

              // Migration for Multiclass if uploading old file
              if (!parsed.classes || !Array.isArray(parsed.classes) || parsed.classes.length === 0) {
                 parsed.classes = [{
                    id: 'migrated-upload-1',
                    name: parsed.class || 'Fighter',
                    level: parsed.level || 1,
                    subclass: parsed.subclass || ''
                 }];
              }

              const merged = { ...INITIAL_CHARACTER, ...parsed };
              merged.proficiencies = parsed.proficiencies; 

              setCharacter(merged);
          } catch (err) {
              console.error("Failed to parse uploaded JSON", err);
              alert("Invalid JSON file");
          }
      };
      reader.readAsText(file);
      e.target.value = '';
  };

  if (!user) {
      return <AuthScreen />;
  }

  const totalLevel = getTotalLevel(character.classes);
  const profBonus = calculateProficiencyBonus(totalLevel);
  const passivePerception = 10 + calculateModifier(character.abilities.WIS) + (character.proficiencies.has('Perception') ? profBonus : 0);

  return (
    <div className="container mx-auto max-w-7xl p-4 bg-white">

      {/* HEADER */}
      <Header 
        data={character} 
        onChange={updateField} 
        onSave={handleSave}
        onDownload={handleDownload}
        onUpload={handleUpload}
        onLogout={logout}
        username={user.username}
        isTouchMode={isTouchMode}
        onToggleTouchMode={() => setIsTouchMode(!isTouchMode)}
      />

      {/* MAIN 3-COLUMN LAYOUT */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 items-stretch">

        {/* LEFT COLUMN (3/12) */}
        <div className="lg:col-span-3 flex flex-col gap-4">
             {/* Inspiration & Passive */}
             <div className="flex flex-col gap-2">
                <div className="flex items-center justify-between bg-white border border-gray-300 rounded-full px-3 py-1 shadow-sm">
                    <span className="text-[10px] uppercase font-bold text-gray-500">{t('stats.inspiration')}</span>
                    <input 
                        type="checkbox" 
                        checked={character.inspiration} 
                        onChange={(e) => updateField('inspiration', e.target.checked)}
                        className="w-5 h-5 accent-dnd-red"
                    />
                </div>
                <div className="flex items-center justify-between bg-white border border-gray-300 rounded px-3 py-1 shadow-sm">
                    <span className="text-[10px] uppercase font-bold text-gray-500">{t('stats.proficiency')}</span>
                    <span className="font-bold text-lg">+{profBonus}</span>
                </div>
                <div className="flex items-center justify-between bg-white border border-gray-300 rounded px-3 py-1 shadow-sm">
                    <span className="text-[10px] uppercase font-bold text-gray-500">{t('stats.passivePerception')}</span>
                    <span className="font-bold text-lg">{passivePerception}</span>
                </div>
             </div>

             {/* Ability Scores - White BG */}
             <div className="bg-white p-2 rounded-lg border border-gray-300 shadow-sm">
                {ABILITIES.map(ability => (
                    <AbilityScoreRow
                        key={ability}
                        ability={ability}
                        score={character.abilities[ability]}
                        profBonus={profBonus}
                        proficiencies={character.proficiencies}
                        onChangeScore={(val) => updateAbility(ability, val)}
                        onToggleProficiency={toggleProficiency}
                    />
                ))}
             </div>

             <ProficienciesBox data={character} onChange={updateField} />
        </div>


        {/* CENTER COLUMN (5/12) */}
        <div className="lg:col-span-5 flex flex-col gap-4">

            <Vitals 
                data={character} 
                onChange={updateField} 
                profBonus={profBonus}
            />

            <div className="flex-1 min-h-[300px]">
                <Attacks 
                    attacks={character.attacks} 
                    onUpdate={(atks) => updateField('attacks', atks)}
                />
            </div>

            <div className="flex-none">
                <Equipment data={character} onChange={updateField} />
            </div>
        </div>


        {/* RIGHT COLUMN (4/12) */}
        {/* Use h-full to stretch to match the tallest column (likely left/center), and min-h-screen to ensure it's big enough on start */}
        <div className="lg:col-span-4 flex flex-col gap-4 h-full min-h-[80vh]">
             <div className="flex-none">
                 <Personality data={character} onChange={updateField} />
             </div>

             {/* Features now takes available space */}
             <div className="flex-1">
                 <FeaturesBox data={character} onChange={(val) => updateField('features', val)} />
             </div>

             {/* Backstory now takes available space */}
             <div className="flex-1">
                 <BackstoryGenerator 
                    data={character}
                    onUpdate={(story) => updateField('backstory', story)}
                 />
             </div>
        </div>
      </div>

      {/* Bottom Section: Spells Table */}
      <SpellList data={character} onChange={updateField} profBonus={profBonus} />

      <footer className="mt-12 text-center text-gray-400 text-xs pb-4">
        <p>&copy; {new Date().getFullYear()} {t('footer.text')}</p>
      </footer>
    </div>
  );
}

import React from 'react';
import { AbilityName } from '../types';
import { calculateModifier, formatModifier } from '../utils/dndCalculations';
import { SKILLS } from '../constants';
import { useLanguage } from '../contexts/LanguageContext';

interface AbilityScoreRowProps {
  ability: AbilityName;
  score: number;
  profBonus: number;
  proficiencies: Set<string>;
  onChangeScore: (val: number) => void;
  onToggleProficiency: (key: string) => void;
  isTouchMode: boolean;
}

export const AbilityScoreRow: React.FC<AbilityScoreRowProps> = ({
  ability,
  score,
  profBonus,
  proficiencies,
  onChangeScore,
  onToggleProficiency,
  isTouchMode,
}) => {
  const { t } = useLanguage();
  const mod = calculateModifier(score);
  const saveMod = mod + (proficiencies.has(ability) ? profBonus : 0);

  // Filter skills for this ability
  const abilitySkills = SKILLS.filter(s => s.ability === ability);

  return (
    <div className="flex flex-row items-center gap-4 mb-4">
      {/* Left: Ability Score Box */}
      <div className="flex flex-col items-center justify-center w-24 relative">
        <div className="border-2 border-gray-400 rounded-xl w-24 h-28 flex flex-col items-center bg-white relative shadow-sm">

           {/* Label inside top */}
           <span className="text-[10px] uppercase font-bold text-gray-500 mt-1">{ability}</span>

           {/* Modifier (Top, geometric shape) */}
           <div className="relative z-10 -mt-1 mb-1">
             <div className="w-16 h-10 bg-white border border-gray-400 flex items-center justify-center clip-trapezoid shadow-sm">
                <span className="text-xl font-bold font-serif">{formatModifier(mod)}</span>
             </div>
           </div>

           {/* Score (Bottom, big number) */}
           <div className="relative w-full flex justify-center items-center flex-1 mb-2 px-1">
               {isTouchMode && (
                   <button 
                       onClick={() => onChangeScore(score - 1)}
                       className="absolute left-1 w-6 h-8 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded flex items-center justify-center font-bold text-lg z-10"
                   >
                       -
                   </button>
               )}
               <input
                  type="number"
                  value={score}
                  onChange={(e) => onChangeScore(parseInt(e.target.value) || 0)}
                  className="text-3xl font-bold text-center w-full bg-transparent outline-none font-serif z-0"
               />
               {isTouchMode && (
                   <button 
                       onClick={() => onChangeScore(score + 1)}
                       className="absolute right-1 w-6 h-8 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded flex items-center justify-center font-bold text-lg z-10"
                   >
                       +
                   </button>
               )}
           </div>
        </div>

        {/* Helper Badge for Score */}
        <div className="bg-white px-2 py-0.5 rounded-full border border-gray-300 text-[10px] -mt-3 z-20 font-bold text-gray-500 uppercase">
          {t('stats.score')}
        </div>
      </div>

      {/* Right: Skills & Save */}
      <div className="flex-1 flex flex-col gap-1">
         {/* Saving Throw Row */}
         <div className="flex items-center text-sm mb-1">
            <input 
                type="checkbox" 
                checked={proficiencies.has(ability)} 
                onChange={() => onToggleProficiency(ability)}
                className="w-4 h-4 rounded-full border-gray-400 mr-2 accent-black"
            />
            <span className="w-6 text-center border-b border-gray-300 mr-2 font-mono">{formatModifier(saveMod)}</span>
            <span className="font-bold text-gray-700">{t('stats.savingThrows')}</span>
         </div>

         {/* Skill Rows */}
         {abilitySkills.map(skill => {
            let skillMod = mod;
            if (proficiencies.has(skill.name)) skillMod += profBonus;

            return (
                <div key={skill.name} className="flex items-center text-sm">
                    <input 
                        type="checkbox" 
                        checked={proficiencies.has(skill.name)} 
                        onChange={() => onToggleProficiency(skill.name)}
                        className="w-4 h-4 rounded-full border-gray-400 mr-2 accent-black"
                    />
                    <span className="w-6 text-center border-b border-gray-300 mr-2 font-mono text-gray-600">
                        {formatModifier(skillMod)}
                    </span>
                    <span className="text-gray-800">{t(`skills.${skill.name}` as any)}</span>
                </div>
            )
         })}
      </div>
    </div>
  );
};

import React from 'react';
import { CharacterData } from '../types';
import { calculateModifier, calculateMaxHP, getTotalLevel } from '../utils/dndCalculations';
import { useLanguage } from '../contexts/LanguageContext';

interface VitalsProps {
  data: CharacterData;
  onChange: (field: keyof CharacterData, value: any) => void;
  profBonus: number;
  isTouchMode: boolean;
}

export const Vitals: React.FC<VitalsProps> = ({ data, onChange, isTouchMode }) => {
  const { t } = useLanguage();
  const dexMod = calculateModifier(data.abilities.DEX);

  // New AC Logic: Base (or 10) + Dex + Bonus
  const baseArmor = data.armorBase || 10;
  const armorBonus = data.armorBonus || 0;
  const calculatedAC = baseArmor + dexMod + armorBonus;
  const finalAC = data.acOverride !== null ? data.acOverride : calculatedAC;

  // HP Calc supports multiclass
  const maxHP = calculateMaxHP(data.classes, data.abilities.CON, data.hpMaxOverride);
  const totalLevel = getTotalLevel(data.classes);

  const initiative = data.initiativeOverride !== null ? data.initiativeOverride : dexMod;
  const initiativeDisplay = initiative >= 0 ? `+${initiative}` : `${initiative}`;

  const updateDeathSave = (type: 'success' | 'failures', index: number) => {
    const arr = [...data.deathSaves[type]];
    arr[index] = !arr[index];
    onChange('deathSaves', { ...data.deathSaves, [type]: arr });
  };

  const SpinButton = ({ onClick, label }: { onClick: () => void, label: string }) => (
      <button 
        onClick={onClick}
        className="bg-gray-100 hover:bg-gray-200 text-gray-600 font-bold px-3 py-1 rounded select-none"
      >
        {label}
      </button>
  );

  return (
    <div className="bg-white p-2 rounded-lg border border-gray-300 shadow-sm">
      {/* Top Row: AC, Init, Speed */}
      <div className="grid grid-cols-3 gap-2 mb-2">
        {/* AC */}
        <div className="border-2 border-gray-400 bg-white rounded-t-none rounded-b-3xl p-2 flex flex-col items-center relative group shadow-sm h-32 justify-between">
          <div className="text-[10px] font-bold text-gray-500 uppercase mt-1">{t('vitals.ac')}</div>
          <span className="text-4xl font-bold font-serif">{finalAC}</span>

          <div className="flex gap-1 w-full px-1">
             <div className="flex flex-col items-center w-1/2">
                <input 
                    type="number" 
                    className="w-full text-center text-xs border-b border-gray-300 outline-none bg-transparent"
                    placeholder={t('vitals.acBase')}
                    value={data.armorBase}
                    onChange={(e) => onChange('armorBase', parseInt(e.target.value) || 0)}
                />
                <span className="text-[8px] text-gray-400 uppercase">{t('vitals.acBase')}</span>
             </div>
             <div className="flex flex-col items-center w-1/2">
                <input 
                    type="number" 
                    className="w-full text-center text-xs border-b border-gray-300 outline-none bg-transparent"
                    placeholder={t('vitals.acBonus')}
                    value={data.armorBonus}
                    onChange={(e) => onChange('armorBonus', parseInt(e.target.value) || 0)}
                />
                <span className="text-[8px] text-gray-400 uppercase">{t('vitals.acBonus')}</span>
             </div>
          </div>
        </div>

        {/* Initiative */}
        <div className="border-2 border-gray-400 bg-white rounded p-2 flex flex-col items-center justify-start h-24 relative shadow-sm">
          <div className="text-[10px] font-bold text-gray-500 uppercase">{t('vitals.initiative')}</div>
          <span className="text-3xl font-bold font-serif mt-2">{initiativeDisplay}</span>
          {isTouchMode && (
              <div className="absolute bottom-1 w-full flex justify-center gap-1">
                  <input 
                    type="number" 
                    placeholder="Ovr"
                    className="w-10 text-center text-xs border border-gray-300 rounded"
                    value={data.initiativeOverride ?? ''}
                    onChange={(e) => onChange('initiativeOverride', e.target.value ? parseInt(e.target.value) : null)}
                  />
              </div>
          )}
        </div>

        {/* Speed */}
        <div className="border-2 border-gray-400 bg-white rounded p-2 flex flex-col items-center justify-start h-24 relative shadow-sm">
          <div className="text-[10px] font-bold text-gray-500 uppercase">{t('vitals.speed')}</div>
          <input 
             type="text"
             className="text-3xl font-bold font-serif mt-2 text-center w-full outline-none bg-transparent"
             value={data.speed}
             onChange={(e) => onChange('speed', e.target.value)}
          />
        </div>
      </div>

      {/* HP Section */}
      <div className="border border-gray-300 bg-white rounded p-2 mb-2">
         <div className="flex justify-between items-center border-b border-gray-200 pb-1 mb-2">
            <span className="text-[10px] font-bold text-gray-500 uppercase">{t('vitals.hp')}</span>
            <div className="flex items-center gap-2">
                 <span className="text-[10px] text-gray-400 uppercase">{t('vitals.hpMax')}:</span>
                 <input 
                    type="number" 
                    placeholder={maxHP.toString()}
                    className="w-12 border-b border-gray-300 text-right text-xs"
                    value={data.hpMaxOverride ?? ''}
                    onChange={(e) => onChange('hpMaxOverride', e.target.value ? parseInt(e.target.value) : null)}
                 />
            </div>
         </div>
         <div className="flex gap-2 items-center">
            {isTouchMode && <SpinButton onClick={() => onChange('hpCurrent', data.hpCurrent - 1)} label="-" />}
            <input 
                type="number" 
                className="flex-1 text-4xl font-serif text-center outline-none"
                value={data.hpCurrent}
                onChange={(e) => onChange('hpCurrent', parseInt(e.target.value) || 0)}
                placeholder={t('vitals.hpCurrent')}
            />
            {isTouchMode && <SpinButton onClick={() => onChange('hpCurrent', data.hpCurrent + 1)} label="+" />}
         </div>
         <div className="text-center text-[10px] text-gray-500 uppercase font-bold">{t('vitals.hpCurrent')}</div>

         {isTouchMode && (
             <div className="flex justify-center gap-2 mt-2">
                  <button onClick={() => onChange('hpCurrent', data.hpCurrent - 5)} className="text-xs bg-gray-100 px-2 py-1 rounded text-gray-600">-5</button>
                  <button onClick={() => onChange('hpCurrent', data.hpCurrent + 5)} className="text-xs bg-gray-100 px-2 py-1 rounded text-gray-600">+5</button>
                  <button onClick={() => onChange('hpCurrent', maxHP)} className="text-xs bg-gray-100 px-2 py-1 rounded text-gray-600">Reset</button>
             </div>
         )}
      </div>

       {/* Temp HP */}
       <div className="border border-gray-300 bg-white rounded p-2 mb-2">
         <input 
            type="text"
            className="w-full text-center text-xl font-serif outline-none"
            value={data.hpTemp}
            onChange={(e) => onChange('hpTemp', e.target.value)}
            placeholder="--"
         />
         <div className="text-center text-[10px] text-gray-500 uppercase font-bold mt-1">{t('vitals.hpTemp')}</div>
       </div>

       {/* HD and Death Saves */}
       <div className="grid grid-cols-2 gap-2">
          {/* Hit Dice */}
          <div className="border border-gray-300 bg-white rounded p-2">
             <div className="flex justify-between text-[10px] text-gray-500 uppercase font-bold mb-1">
                <span>{t('vitals.hitDice')}</span>
                <span className="text-[9px]">{t('vitals.total')}: {totalLevel}</span>
             </div>
             <div className="flex flex-col gap-1">
                 <input 
                    type="text" 
                    className="w-full text-center border-b border-gray-200 text-sm"
                    placeholder="e.g. 5d10"
                    value={data.hitDiceTotal}
                    onChange={(e) => onChange('hitDiceTotal', e.target.value)}
                 />
                 <input 
                    type="text" 
                    className="w-full text-center border-b border-gray-200 text-sm"
                    placeholder={t('vitals.used')}
                    value={data.hitDiceUsed}
                    onChange={(e) => onChange('hitDiceUsed', e.target.value)}
                 />
             </div>
          </div>

          {/* Death Saves */}
          <div className="border border-gray-300 bg-white rounded p-2">
             <div className="text-[10px] text-gray-500 uppercase font-bold mb-1 text-center">{t('vitals.deathSaves')}</div>

             <div className="flex justify-between items-center text-xs mb-1">
                <span className="text-[10px] uppercase font-bold text-gray-400">{t('vitals.success')}</span>
                <div className="flex gap-1">
                    {[0, 1, 2].map(i => (
                        <input key={i} type="checkbox" checked={data.deathSaves.success[i]} onChange={() => updateDeathSave('success', i)} className="accent-green-600 w-3 h-3"/>
                    ))}
                </div>
             </div>
             <div className="flex justify-between items-center text-xs">
                <span className="text-[10px] uppercase font-bold text-gray-400">{t('vitals.failures')}</span>
                <div className="flex gap-1">
                    {[0, 1, 2].map(i => (
                        <input key={i} type="checkbox" checked={data.deathSaves.failures[i]} onChange={() => updateDeathSave('failures', i)} className="accent-red-600 w-3 h-3"/>
                    ))}
                </div>
             </div>
          </div>
       </div>

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { AbilityScoreRow } from './components/AbilityScore';
import { Vitals } from './components/Vitals';
import { Personality } from './components/Personality';
import { Attacks } from './components/Attacks';
import { ProficienciesBox } from './components/ProficienciesBox';
import { Equipment } from './components/Equipment';
import { FeaturesBox } from './components/FeaturesBox';
import { SpellList } from './components/SpellList';
import { BackstoryGenerator } from './components/BackstoryGenerator';
import { AuthScreen } from './components/AuthScreen';
import { CharacterData, INITIAL_CHARACTER, AbilityName } from './types';
import { calculateProficiencyBonus, calculateModifier, getTotalLevel } from './utils/dndCalculations';
import { ABILITIES } from './constants';
import { useLanguage } from './contexts/LanguageContext';
import { useAuth } from './contexts/AuthContext';

export default function App() {
  const [character, setCharacter] = useState<CharacterData>(INITIAL_CHARACTER);
  const [isTouchMode, setIsTouchMode] = useState(false);
  const { t } = useLanguage();
  const { user, logout } = useAuth();

  // Apply Touch Mode class to body
  useEffect(() => {
    if (isTouchMode) {
      document.body.classList.add('touch-mode');
    } else {
      document.body.classList.remove('touch-mode');
    }
  }, [isTouchMode]);

  // Load data for user
  useEffect(() => {
    if (!user) return;

    const saved = localStorage.getItem(`dnd_data_${user.username}`);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        parsed.proficiencies = new Set(parsed.proficiencies);
        parsed.expertises = new Set(parsed.expertises);

        // Ensure defaults exist for migration
        const defaults = INITIAL_CHARACTER;

        // BACKWARD COMPATIBILITY: Migrate single class to classes array
        if (!parsed.classes || !Array.isArray(parsed.classes) || parsed.classes.length === 0) {
            parsed.classes = [{
                id: 'migrated-1',
                name: parsed.class || 'Fighter',
                level: parsed.level || 1,
                subclass: parsed.subclass || ''
            }];
        }

        if (!parsed.attacks) parsed.attacks = defaults.attacks;
        if (!parsed.currency) parsed.currency = defaults.currency;
        if (!parsed.proficienciesText) parsed.proficienciesText = defaults.proficienciesText;
        if (!parsed.status) parsed.status = defaults.status;
        if (!parsed.deathSaves) parsed.deathSaves = defaults.deathSaves;
        if (parsed.armorBase === undefined) parsed.armorBase = 10;
        if (parsed.armorBonus === undefined) parsed.armorBonus = 0;
        if (parsed.inspiration === undefined) parsed.inspiration = false;

        if (typeof parsed.spells === 'string' || !parsed.spellcasting) {
            parsed.spellcasting = defaults.spellcasting;
            delete parsed.spells;
        }
        if (!parsed.spellcasting.slots) parsed.spellcasting.slots = defaults.spellcasting.slots;

        setCharacter(parsed);
      } catch (e) {
        console.error("Failed to load saved character", e);
        setCharacter(INITIAL_CHARACTER);
      }
    } else {
        setCharacter(INITIAL_CHARACTER);
    }
  }, [user]);

  // Auto-save logic
  useEffect(() => {
    if (!user) return;

    const toSave = {
      ...character,
      proficiencies: Array.from(character.proficiencies),
      expertises: Array.from(character.expertises)
    };
    localStorage.setItem(`dnd_data_${user.username}`, JSON.stringify(toSave));
  }, [character, user]);

  const updateField = (field: keyof CharacterData, value: any) => {
    setCharacter(prev => ({ ...prev, [field]: value }));
  };

  const updateAbility = (ability: AbilityName, val: number) => {
    setCharacter(prev => ({
      ...prev,
      abilities: { ...prev.abilities, [ability]: val }
    }));
  };

  const toggleProficiency = (key: string) => {
    setCharacter(prev => {
      const newProfs = new Set(prev.proficiencies);
      if (newProfs.has(key)) {
        newProfs.delete(key);
      } else {
        newProfs.add(key);
      }
      return { ...prev, proficiencies: newProfs };
    });
  };

  // Header Actions
  const handleSave = () => {
    if (!user) return;
    const toSave = {
        ...character,
        proficiencies: Array.from(character.proficiencies),
        expertises: Array.from(character.expertises)
    };
    localStorage.setItem(`dnd_data_${user.username}`, JSON.stringify(toSave));
    alert(t('header.saved'));
  };

  const handleDownload = () => {
    const toSave = {
        ...character,
        proficiencies: Array.from(character.proficiencies),
        expertises: Array.from(character.expertises)
    };
    const blob = new Blob([JSON.stringify(toSave, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${character.name || 'character'}_sheet.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const parsed = JSON.parse(event.target?.result as string);

              // Validate/Migrate similar to load
              parsed.proficiencies = new Set(parsed.proficiencies);
              parsed.expertises = new Set(parsed.expertises);

              // Migration for Multiclass if uploading old file
              if (!parsed.classes || !Array.isArray(parsed.classes) || parsed.classes.length === 0) {
                 parsed.classes = [{
                    id: 'migrated-upload-1',
                    name: parsed.class || 'Fighter',
                    level: parsed.level || 1,
                    subclass: parsed.subclass || ''
                 }];
              }

              const merged = { ...INITIAL_CHARACTER, ...parsed };
              merged.proficiencies = parsed.proficiencies; 

              setCharacter(merged);
          } catch (err) {
              console.error("Failed to parse uploaded JSON", err);
              alert("Invalid JSON file");
          }
      };
      reader.readAsText(file);
      e.target.value = '';
  };

  if (!user) {
      return <AuthScreen />;
  }

  const totalLevel = getTotalLevel(character.classes);
  const profBonus = calculateProficiencyBonus(totalLevel);
  const passivePerception = 10 + calculateModifier(character.abilities.WIS) + (character.proficiencies.has('Perception') ? profBonus : 0);

  return (
    <div className="container mx-auto max-w-7xl p-4 bg-white">

      {/* HEADER */}
      <Header 
        data={character} 
        onChange={updateField} 
        onSave={handleSave}
        onDownload={handleDownload}
        onUpload={handleUpload}
        onLogout={logout}
        username={user.username}
        isTouchMode={isTouchMode}
        onToggleTouchMode={() => setIsTouchMode(!isTouchMode)}
      />

      {/* MAIN 3-COLUMN LAYOUT */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 items-stretch">

        {/* LEFT COLUMN (3/12) */}
        <div className="lg:col-span-3 flex flex-col gap-4">
             {/* Inspiration & Passive */}
             <div className="flex flex-col gap-2">
                <div className="flex items-center justify-between bg-white border border-gray-300 rounded-full px-3 py-1 shadow-sm">
                    <span className="text-[10px] uppercase font-bold text-gray-500">{t('stats.inspiration')}</span>
                    <input 
                        type="checkbox" 
                        checked={character.inspiration} 
                        onChange={(e) => updateField('inspiration', e.target.checked)}
                        className="w-5 h-5 accent-dnd-red"
                    />
                </div>
                <div className="flex items-center justify-between bg-white border border-gray-300 rounded px-3 py-1 shadow-sm">
                    <span className="text-[10px] uppercase font-bold text-gray-500">{t('stats.proficiency')}</span>
                    <span className="font-bold text-lg">+{profBonus}</span>
                </div>
                <div className="flex items-center justify-between bg-white border border-gray-300 rounded px-3 py-1 shadow-sm">
                    <span className="text-[10px] uppercase font-bold text-gray-500">{t('stats.passivePerception')}</span>
                    <span className="font-bold text-lg">{passivePerception}</span>
                </div>
             </div>

             {/* Ability Scores - White BG */}
             <div className="bg-white p-2 rounded-lg border border-gray-300 shadow-sm">
                {ABILITIES.map(ability => (
                    <AbilityScoreRow
                        key={ability}
                        ability={ability}
                        score={character.abilities[ability]}
                        profBonus={profBonus}
                        proficiencies={character.proficiencies}
                        onChangeScore={(val) => updateAbility(ability, val)}
                        onToggleProficiency={toggleProficiency}
                        isTouchMode={isTouchMode}
                    />
                ))}
             </div>

             <ProficienciesBox data={character} onChange={updateField} />
        </div>


        {/* CENTER COLUMN (5/12) */}
        <div className="lg:col-span-5 flex flex-col gap-4">

            <Vitals 
                data={character} 
                onChange={updateField} 
                profBonus={profBonus}
                isTouchMode={isTouchMode}
            />

            <div className="flex-1 min-h-[300px]">
                <Attacks 
                    attacks={character.attacks} 
                    onUpdate={(atks) => updateField('attacks', atks)}
                />
            </div>

            <div className="flex-none">
                <Equipment data={character} onChange={updateField} />
            </div>
        </div>


        {/* RIGHT COLUMN (4/12) */}
        {/* Use h-full to stretch to match the tallest column (likely left/center), and min-h-screen to ensure it's big enough on start */}
        <div className="lg:col-span-4 flex flex-col gap-4 h-full min-h-[80vh]">
             <div className="flex-none">
                 <Personality data={character} onChange={updateField} />
             </div>

             {/* Features now takes available space */}
             <div className="flex-1">
                 <FeaturesBox data={character} onChange={(val) => updateField('features', val)} />
             </div>

             {/* Backstory now takes available space */}
             <div className="flex-1">
                 <BackstoryGenerator 
                    data={character}
                    onUpdate={(story) => updateField('backstory', story)}
                 />
             </div>
        </div>
      </div>

      {/* Bottom Section: Spells Table */}
      <SpellList data={character} onChange={updateField} profBonus={profBonus} />

      <footer className="mt-12 text-center text-gray-400 text-xs pb-4">
        <p>&copy; {new Date().getFullYear()} {t('footer.text')}</p>
      </footer>
    </div>
  );
}

import React from 'react';
import { AbilityName } from '../types';
import { calculateModifier, formatModifier } from '../utils/dndCalculations';
import { SKILLS } from '../constants';
import { useLanguage } from '../contexts/LanguageContext';

interface AbilityScoreRowProps {
  ability: AbilityName;
  score: number;
  profBonus: number;
  proficiencies: Set<string>;
  onChangeScore: (val: number) => void;
  onToggleProficiency: (key: string) => void;
  isTouchMode: boolean;
}

export const AbilityScoreRow: React.FC<AbilityScoreRowProps> = ({
  ability,
  score,
  profBonus,
  proficiencies,
  onChangeScore,
  onToggleProficiency,
  isTouchMode,
}) => {
  const { t } = useLanguage();
  const mod = calculateModifier(score);
  const saveMod = mod + (proficiencies.has(ability) ? profBonus : 0);

  // Filter skills for this ability
  const abilitySkills = SKILLS.filter(s => s.ability === ability);

  return (
    <div className="flex flex-row items-center gap-4 mb-4">
      {/* Left: Ability Score Box */}
      <div className="flex flex-col items-center justify-center w-24 relative">
        <div className="border-2 border-gray-400 rounded-xl w-24 h-28 flex flex-col items-center bg-white relative shadow-sm">

           {/* Label inside top */}
           <span className="text-[10px] uppercase font-bold text-gray-500 mt-1">{ability}</span>

           {/* Modifier (Top, geometric shape) */}
           <div className="relative z-10 -mt-1 mb-1">
             <div className="w-16 h-10 bg-white border border-gray-400 flex items-center justify-center clip-trapezoid shadow-sm">
                <span className="text-xl font-bold font-serif">{formatModifier(mod)}</span>
             </div>
           </div>

           {/* Score (Bottom, big number) */}
           <div className="relative w-full flex justify-center items-center flex-1 mb-2 px-1">
               <div className="flex items-center justify-center">
                   <input
                      type="number"
                      value={score}
                      onChange={(e) => onChangeScore(parseInt(e.target.value) || 0)}
                      className={`text-3xl font-bold text-center w-12 bg-transparent outline-none font-serif z-0 p-0 ${isTouchMode ? 'no-native-spinner' : ''}`}
                   />
                   {isTouchMode && (
                       <div className="flex flex-col gap-0.5 ml-0.5">
                           <button 
                               onClick={() => onChangeScore(score + 1)}
                               className="w-5 h-3.5 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded-t border border-gray-300 flex items-center justify-center text-[8px] leading-none active:bg-gray-300"
                           >
                               ▲
                           </button>
                           <button 
                               onClick={() => onChangeScore(score - 1)}
                               className="w-5 h-3.5 bg-gray-100 hover:bg-gray-200 text-gray-600 rounded-b border border-gray-300 border-t-0 flex items-center justify-center text-[8px] leading-none active:bg-gray-300"
                           >
                               ▼
                           </button>
                       </div>
                   )}
               </div>
           </div>
        </div>

        {/* Helper Badge for Score */}
        <div className="bg-white px-2 py-0.5 rounded-full border border-gray-300 text-[10px] -mt-3 z-20 font-bold text-gray-500 uppercase">
          {t('stats.score')}
        </div>
      </div>

      {/* Right: Skills & Save */}
      <div className="flex-1 flex flex-col gap-1">
         {/* Saving Throw Row */}
         <div className="flex items-center text-sm mb-1">
            <input 
                type="checkbox" 
                checked={proficiencies.has(ability)} 
                onChange={() => onToggleProficiency(ability)}
                className="w-4 h-4 rounded-full border-gray-400 mr-2 accent-black"
            />
            <span className="w-6 text-center border-b border-gray-300 mr-2 font-mono">{formatModifier(saveMod)}</span>
            <span className="font-bold text-gray-700">{t('stats.savingThrows')}</span>
         </div>

         {/* Skill Rows */}
         {abilitySkills.map(skill => {
            let skillMod = mod;
            if (proficiencies.has(skill.name)) skillMod += profBonus;

            return (
                <div key={skill.name} className="flex items-center text-sm">
                    <input 
                        type="checkbox" 
                        checked={proficiencies.has(skill.name)} 
                        onChange={() => onToggleProficiency(skill.name)}
                        className="w-4 h-4 rounded-full border-gray-400 mr-2 accent-black"
                    />
                    <span className="w-6 text-center border-b border-gray-300 mr-2 font-mono text-gray-600">
                        {formatModifier(skillMod)}
                    </span>
                    <span className="text-gray-800">{t(`skills.${skill.name}` as any)}</span>
                </div>
            )
         })}
      </div>
    </div>
  );
};

